import { NextResponse } from 'next/server';
import { sendLeadEmail } from '@/lib/mail';
import { business, formatFullAddress } from '@/lib/business';
import {
  isValidEmail,
  isValidPhone,
  safeEnum,
  safeTrim,
} from '@/lib/validators';

export const runtime = 'nodejs';

const preferredContactOptions = ['call', 'text', 'email'] as const;
type PreferredContact = (typeof preferredContactOptions)[number];

export async function POST(req: Request) {
  try {
    const body = await req.json().catch(() => ({}));

    // Honeypot: include an invisible input named "website" in your form.
    // If it’s filled, treat as bot and return OK without sending.
    const honeypot = safeTrim(body.website, 200);
    if (honeypot) return NextResponse.json({ ok: true }, { status: 200 });

    const name = safeTrim(body.name, 120);
    const phone = safeTrim(body.phone, 30);
    const email = safeTrim(body.email, 200);
    const device = safeTrim(body.device, 120);
    const issue = safeTrim(body.issue, 2000);
    const preferredContact = safeEnum<PreferredContact>(
      body.preferredContact,
      preferredContactOptions,
      'text'
    );

    // Required fields
    if (!name) return NextResponse.json({ error: 'Name is required.' }, { status: 400 });
    if (!phone) return NextResponse.json({ error: 'Phone is required.' }, { status: 400 });
    if (!device) return NextResponse.json({ error: 'Device is required.' }, { status: 400 });
    if (!issue) return NextResponse.json({ error: 'Issue is required.' }, { status: 400 });

    // Validate phone/email if provided
    if (phone && !isValidPhone(phone)) {
      return NextResponse.json({ error: 'Invalid phone number.' }, { status: 400 });
    }
    if (email && !isValidEmail(email)) {
      return NextResponse.json({ error: 'Invalid email address.' }, { status: 400 });
    }

    const subject = `New Quote Request — ${device} (${name})`;

    const html = `
      <div style="font-family: Arial, sans-serif; line-height: 1.4;">
        <h2 style="margin:0 0 12px 0;">New Quote Request</h2>

        <table cellpadding="0" cellspacing="0" style="border-collapse: collapse;">
          <tr><td style="padding:4px 12px 4px 0;"><b>Name:</b></td><td>${esc(name)}</td></tr>
          <tr><td style="padding:4px 12px 4px 0;"><b>Phone:</b></td><td>${esc(phone)}</td></tr>
          <tr><td style="padding:4px 12px 4px 0;"><b>Email:</b></td><td>${esc(email || '(not provided)')}</td></tr>
          <tr><td style="padding:4px 12px 4px 0;"><b>Device:</b></td><td>${esc(device)}</td></tr>
          <tr><td style="padding:4px 12px 4px 0;"><b>Preferred contact:</b></td><td>${esc(preferredContact)}</td></tr>
        </table>

        <div style="margin-top:12px;">
          <b>Issue details:</b>
          <div style="margin-top:6px; padding:10px; background:#f6f7f8; border:1px solid #e6e6e6; border-radius:8px;">
            ${esc(issue).replace(/\n/g, '<br/>')}
          </div>
        </div>

        <hr style="margin:16px 0; border:none; border-top:1px solid #e6e6e6;" />

        <div style="color:#555; font-size: 12px;">
          Sent from <b>${esc(business.name)}</b><br/>
          ${esc(formatFullAddress())}<br/>
          ${esc(business.phoneDisplay)}
        </div>
      </div>
    `;

    await sendLeadEmail({
      subject,
      html,
      replyTo: email || undefined,
    });

    return NextResponse.json({ ok: true }, { status: 200 });
  } catch (err: any) {
    return NextResponse.json(
      { error: err?.message || 'Failed to submit quote request.' },
      { status: 500 }
    );
  }
}

function esc(s: string) {
  return s
    .replaceAll('&', '&amp;')
    .replaceAll('<', '&lt;')
    .replaceAll('>', '&gt;')
    .replaceAll('"', '&quot;')
    .replaceAll("'", '&#039;');
}
